def norm_text(s): 
    return normalize_arabic(s)

def lcs_len(a, b):
    # compute LCS length
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            temp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = temp
    return dp[m]

def lcs_ratio(a, b):
    a_norm = norm_text(a)
    b_norm = norm_text(b)
    L = lcs_len(a_norm, b_norm)
    return L / max(1, max(len(a_norm), len(b_norm)))

def token_f1(a, b):
    a_tokens = norm_text(a).split()
    b_tokens = norm_text(b).split()
    a_set = set(a_tokens)
    b_set = set(b_tokens)
    inter = a_set & b_set
    if not a_set and not b_set:
        return 1.0
    prec = len(inter)/len(a_set) if a_set else 0.0
    rec = len(inter)/len(b_set) if b_set else 0.0
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

